      {
        "scenario": "Slow degradation — renewals process but increasingly late, breaching the 1-hour SLO",
        "handling": "unhandled",
        "recommendation": "Add renewal_scheduling_lag_seconds histogram (processed_time - scheduled_time). Alert on p99 exceeding 30 minutes (50% of SLO budget). This is the single most important missing metric."
      },
